  ('slas_hn', 'Requisitos Para Licenciamiento Ambiental SLAS 2 · Listado de Requisitos · Requisito 2: Escrito De Solicitud De Licencia Ambiental.', '2. Escrito De Solicitud De Licencia Ambiental.', 'honduras-ambiental/03-slas-nuevos-requisitos.md', '{"doc_label":"Sistema de Licenciamiento Ambiental Simplificado SLAS-2 (Honduras)","fuente_pdf":"bef954bc-Nuevos_Requisitos_SLAS.pdf","decreto":null,"acuerdo":"No especificado en el documento fuente","emisor":"Secretaría de Energía, Recursos Naturales, Ambiente y Minas — Gobierno de la República de Honduras (Presidenta Xiomara Castro)","gaceta":null,"fecha":"No especificada en el documento fuente","subcategoria":"slas_licenciamiento_ambiental_simplificado","chunk_index":3,"chunk_total":31}'::jsonb),
