  ('slas_hn', 'Requisitos Para Licenciamiento Ambiental SLAS 2 · Listado de Requisitos · Requisito 15: Herramienta Técnica De Acuerdo A La Categoría Del Proyecto: Memoria Técnica, Pla', '15. Herramienta Técnica De Acuerdo A La Categoría Del Proyecto: Memoria Técnica, Plan De Gestión Ambiental, Estudio De Impacto Ambiental; (Documentación Categoría 4; Socialización Y Aprobación De Acta De Cabildo Abierto Con Fotografías Y Listados, Publicación De Avisos De Inicio Y Finalización Del Estudio De Impacto Ambiental, Spot Publicitarios Durante 5 Días En Radios Locales Y Nacionales, Constancia De INGHEOMIN Y Para Camaricultores Constancia De La SAG).', 'honduras-ambiental/03-slas-nuevos-requisitos.md', '{"doc_label":"Sistema de Licenciamiento Ambiental Simplificado SLAS-2 (Honduras)","fuente_pdf":"bef954bc-Nuevos_Requisitos_SLAS.pdf","decreto":null,"acuerdo":"No especificado en el documento fuente","emisor":"Secretaría de Energía, Recursos Naturales, Ambiente y Minas — Gobierno de la República de Honduras (Presidenta Xiomara Castro)","gaceta":null,"fecha":"No especificada en el documento fuente","subcategoria":"slas_licenciamiento_ambiental_simplificado","chunk_index":16,"chunk_total":31}'::jsonb),
